```python
def factorial(n):
    if n == 0 or n == 1:
        return 1
    else:
        result = 1
        for i in range(2, n + 1):
            result *= i
        return result
```

```python
def clamp(x, lo, hi):
    return max(lo, min(x, hi))
```

```python
def unique(lst):
    seen = set()
    result = []
    for item in lst:
        if item not in seen:
            seen.add(item)
            result.append(item)
    return result
```

```python
def dot_product(a, b):
    if len(a) != len(b):
        raise ValueError("Both lists must have the same length")
    return sum(x * y for x, y in zip(a, b))
```

```python
def char_frequency(s):
    frequency = {}
    for char in s:
        if char in frequency:
            frequency[char] += 1
        else:
            frequency[char] = 1
    return frequency
```
